namespace DocSummary.Models;

public class SummarizeRequest
{
    public required string DocumentText { get; set; }
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public required string Summary { get; set; }
    public int OriginalLength { get; set; }
    public int SummaryLength { get; set; }
}

namespace DocSummary.Services;

public class DocumentSummaryService
{
    /// <summary>
    /// Produces an extractive summary by scoring sentences on word frequency
    /// and returning the top-ranked ones in their original order.
    /// </summary>
    public string Summarize(string documentText, int maxSentences = 3)
    {
        if (string.IsNullOrWhiteSpace(documentText))
            return string.Empty;

        var sentences = SplitIntoSentences(documentText);

        if (sentences.Count <= maxSentences)
            return string.Join(" ", sentences);

        var wordFrequencies = BuildWordFrequencies(sentences);
        var scored = ScoreSentences(sentences, wordFrequencies);

        // Pick the top-scoring sentences but preserve original order.
        var topIndices = scored
            .OrderByDescending(s => s.Score)
            .Take(maxSentences)
            .Select(s => s.Index)
            .OrderBy(i => i)
            .ToList();

        return string.Join(" ", topIndices.Select(i => sentences[i]));
    }

    private static List<string> SplitIntoSentences(string text)
    {
        return text
            .Split(['.', '!', '?'], StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
            .Where(s => s.Length > 0)
            .Select(s => s + ".")
            .ToList();
    }

    private static Dictionary<string, int> BuildWordFrequencies(List<string> sentences)
    {
        var frequencies = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);

        foreach (var sentence in sentences)
        {
            foreach (var word in GetWords(sentence))
            {
                if (word.Length <= 2) continue; // skip very short words
                frequencies[word] = frequencies.GetValueOrDefault(word) + 1;
            }
        }

        return frequencies;
    }

    private static List<(int Index, double Score)> ScoreSentences(
        List<string> sentences, Dictionary<string, int> wordFrequencies)
    {
        var scored = new List<(int Index, double Score)>();

        for (int i = 0; i < sentences.Count; i++)
        {
            double score = GetWords(sentences[i])
                .Where(w => w.Length > 2)
                .Sum(w => wordFrequencies.GetValueOrDefault(w));

            scored.Add((i, score));
        }

        return scored;
    }

    private static IEnumerable<string> GetWords(string text)
    {
        return text.Split([' ', ',', ';', ':', '"', '\'', '(', ')', '[', ']', '\n', '\r', '\t'],
            StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries);
    }
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummaryController : ControllerBase
{
    private readonly DocumentSummaryService _summaryService;

    public SummaryController(DocumentSummaryService summaryService)
    {
        _summaryService = summaryService;
    }

    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.DocumentText))
            return BadRequest("DocumentText is required.");

        var summary = _summaryService.Summarize(request.DocumentText, request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalLength = request.DocumentText.Length,
            SummaryLength = summary.Length
        });
    }
}

